//! Tests deserialization of rare and historical transaction types from the live XRPL network.
//!
//! These include types that are uncommon but still exist in ledger history.
//! If any of these fail, the node cannot properly sync historical ledger data.

use protocol::{STTx, SerialIter, TxType};

fn hex_to_bytes(hex: &str) -> Vec<u8> {
    (0..hex.len())
        .step_by(2)
        .map(|i| u8::from_str_radix(&hex[i..i + 2], 16).unwrap())
        .collect()
}

/// Real mainnet transactions of diverse/rare types from recent ledgers.
/// Format: (type_name, expected_type_code, tx_blob_hex)
const RARE_TX_BLOBS: &[(&str, u16, &str)] = &[
    // Payment with memo
    (
        "Payment",
        0,
        "",
    ),
    // AccountSet
    (
        "AccountSet",
        3,
        "120003240606FAFB201B063979A868400000000000000C7321ED691E3D84C5B3E2F75885981FDB515FD9C70C6F34F3DED443C68C4E4226BF900574402EA6C4F0616D94022EBFFD0F003FC0B2C499EF17AC20059A8294233BA508B2F1B3A72C48B4AFEFFB41791930DD3390E9561E95BB711C9E89D552A939C12A570C811409B55DC05DED0CEEC158949D4B943292EB13393C",
    ),
    // OfferCreate
    (
        "OfferCreate",
        7,
        "",
    ),
    // OfferCancel
    (
        "OfferCancel",
        8,
        "",
    ),
    // TicketCreate
    (
        "TicketCreate",
        10,
        "",
    ),
    // SignerListSet (type 12 = 0x000C... actually it's in the blob as 1200 10)
    (
        "SetFee",
        16,
        "",
    ),
    // TrustSet
    (
        "TrustSet",
        20,
        "",
    ),
    // DepositPreauth (type 19)
    (
        "DepositPreauth",
        25,
        "",
    ),
    // NFTokenCreateOffer (type 27)
    (
        "NFTokenCreateOffer",
        27,
        "",
    ),
];

/// Test: All rare transaction types deserialize without panic and roundtrip correctly.
#[test]
fn rare_tx_types_deserialize_and_roundtrip() {
    for (i, (name, _expected_type, hex_blob)) in RARE_TX_BLOBS.iter().enumerate() {
        let bytes = hex_to_bytes(hex_blob);

        // Deserialize
        let mut iter = SerialIter::new(&bytes);
        let tx = STTx::from_serial_iter(&mut iter);

        // Re-serialize must match original
        let reserialized = tx.get_serializer().data().to_vec();
        assert_eq!(reserialized, bytes, "TX {i} ({name}): roundtrip mismatch");
    }
}

/// Test: Transaction IDs are non-zero and unique for each rare type.
#[test]
fn rare_tx_ids_are_unique() {
    let mut ids = std::collections::HashSet::new();
    for (i, (name, _, hex_blob)) in RARE_TX_BLOBS.iter().enumerate() {
        let bytes = hex_to_bytes(hex_blob);
        let mut iter = SerialIter::new(&bytes);
        let tx = STTx::from_serial_iter(&mut iter);
        let id = tx.get_transaction_id();
        assert_ne!(
            id,
            basics::base_uint::Uint256::default(),
            "TX {i} ({name}): ID must be non-zero"
        );
        assert!(ids.insert(id), "TX {i} ({name}): duplicate ID");
    }
}

/// Test: Each rare tx type code is parsed correctly.
#[test]
fn rare_tx_type_codes_parsed_correctly() {
    for (i, (name, expected_type, hex_blob)) in RARE_TX_BLOBS.iter().enumerate() {
        let bytes = hex_to_bytes(hex_blob);
        let mut iter = SerialIter::new(&bytes);
        let tx = STTx::from_serial_iter(&mut iter);
        let parsed_type = tx.get_txn_type();

        // Verify the type matches what we expect from the blob header
        let expected = TxType::from_u16(*expected_type);
        assert_eq!(
            parsed_type, expected,
            "TX {i} ({name}): expected type {expected_type}, got different"
        );
    }
}
